1	import { existsSync } from "node:fs";
2	import { dirname, join, resolve } from "node:path";
3	
4	const TRACKGENTIC_DIR = ".trackgentic";
5	
6	/**
7	 * Walk up from `cwd` looking for a `.trackgentic/` directory.
8	 * Returns the absolute path to `.trackgentic/` if found, or `null` if not found.
9	 * Stops at filesystem root.
10	 */
11	export function resolveTrackerDir(cwd: string): string | null {
12	  let current = resolve(cwd);
13	
14	  while (true) {
15	    const candidate = join(current, TRACKGENTIC_DIR);
16	    if (existsSync(candidate)) {
17	      return candidate;
18	    }
19	
20	    const parent = dirname(current);
21	    if (parent === current) {
22	      // Reached filesystem root
23	      return null;
24	    }
25	    current = parent;
26	  }
27	}
