1	import { existsSync, mkdirSync } from "node:fs";
2	import { join, resolve } from "node:path";
3	import type { ConfigFile, DependenciesFile, IndexFile, InitResult, UsersFile } from "../types";
4	import { atomicWriteJSON } from "./file-io";
5	
6	const TRACKGENTIC_DIR = ".trackgentic";
7	
8	/**
9	 * Default config.json contents.
10	 */
11	const DEFAULT_CONFIG: ConfigFile = {
12	  auth: {
13	    mode: "read-only",
14	    defaultUser: "anonymous",
15	  },
16	};
17	
18	/**
19	 * Default index.json contents.
20	 */
21	const DEFAULT_INDEX: IndexFile = {
22	  open: [],
23	  closed: [],
24	  childrenOf: {},
25	};
26	
27	/**
28	 * Default dependencies.json contents.
29	 */
30	const DEFAULT_DEPENDENCIES: DependenciesFile = {
31	  blockedBy: {},
32	  blocks: {},
33	};
34	
35	/**
36	 * Default users.json contents.
37	 */
38	const DEFAULT_USERS: UsersFile = {
39	  users: [],
40	};
41	
42	/**
43	 * Tracker — the main programmatic API for trackgentic.
44	 *
45	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
46	 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
47	 */
48	export class Tracker {
49	  private cwd: string;
50	
51	  constructor(cwd?: string) {
52	    this.cwd = cwd ?? process.cwd();
53	  }
54	
55	  /**
56	   * Initialize a new `.trackgentic/` directory in `cwd`.
57	   *
58	   * Creates the directory with:
59	   * - config.json — default auth config
60	   * - index.json — empty open/closed arrays, empty childrenOf map
61	   * - dependencies.json — empty blockedBy/blocks maps
62	   * - users.json — empty users array
63	   * - issues/ — empty directory
64	   *
65	   * Idempotent: if `.trackgentic/` already exists, returns ALREADY_INITIALIZED
66	   * without overwriting any files.
67	   */
68	  async init(): Promise<InitResult> {
69	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
70	
71	    if (existsSync(trackerDir)) {
72	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
73	    }
74	
75	    // Create the main directory
76	    mkdirSync(trackerDir, { recursive: true });
77	
78	    // Create issues subdirectory
79	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
80	
81	    // Write initial files
82	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
83	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
84	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
85	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
86	
87	    return { result: "OK", path: resolve(trackerDir) };
88	  }
89	}
