1	import type { CommentId, IssueId } from "../types";
2	
3	/**
4	 * Generate a unique issue ID.
5	 * Format: 6 chars from timestamp (base36) + 4 random chars (base36) = 10 chars total.
6	 * IDs are sortable by creation time.
7	 */
8	export function generateId(): IssueId {
9	  return Date.now().toString(36).slice(0, 6) + Math.random().toString(36).slice(-4);
10	}
11	
12	/**
13	 * Generate a unique comment ID.
14	 * Uses the same algorithm as issue IDs.
15	 */
16	export function generateCommentId(): CommentId {
17	  return Date.now().toString(36).slice(0, 6) + Math.random().toString(36).slice(-4);
18	}
