import { readFile, writeFile } from "node:fs/promises";
import type { ComputedIssue, Event, IssueId, IssueStatus } from "../types";

/**
 * Append a single event to an issue's JSON file (array of events).
 * Creates the file with a JSON array if it doesn't exist yet.
 */
export async function appendEvent(issuePath: string, event: Event): Promise<void> {
  let events: Event[];

  try {
    const contents = await readFile(issuePath, "utf-8");
    events = JSON.parse(contents) as Event[];
  } catch {
    // File doesn't exist yet — start with empty array
    events = [];
  }

  events.push(event);
  await writeFile(issuePath, `${JSON.stringify(events, null, 2)}\n`, "utf-8");
}

/**
 * Read an issue file and return the raw event array.
 */
export async function replayEvents(issuePath: string): Promise<Event[]> {
  const contents = await readFile(issuePath, "utf-8");
  return JSON.parse(contents) as Event[];
}

/** Default values for a new issue (no events applied yet). */
const DEFAULTS = {
  status: "idea" as IssueStatus,
  priority: 3 as 1 | 2 | 3 | 4 | 5,
  assignee: null as string | null,
  parentId: null as string | null,
  tags: [] as string[],
  description: "",
};

/**
 * Replay events to produce a ComputedIssue.
 *
 * - Creation event: sets createdAt, createdBy.
 * - Update events: merge content fields into properties.
 * - Comment / blockage events: ignored (handled separately).
 * - updatedAt = timestamp of last event.
 *
 * The `id` comes from the filename, not from the events.
 */
export function computeState(events: Event[], issueId: IssueId): ComputedIssue {
  let createdAt = "";
  let createdBy = "";
  let title = "";
  let description = DEFAULTS.description;
  let status = DEFAULTS.status;
  let priority = DEFAULTS.priority;
  let assignee: string | null = DEFAULTS.assignee;
  let parentId: string | null = DEFAULTS.parentId;
  let tags: string[] = [...DEFAULTS.tags];
  let updatedAt = "";

  for (const event of events) {
    updatedAt = event.timestamp;

    switch (event.type) {
      case "creation":
        createdAt = event.timestamp;
        createdBy = event.author;
        break;

      case "update":
        if (event.content.title !== undefined) title = event.content.title;
        if (event.content.description !== undefined) description = event.content.description;
        if (event.content.status !== undefined) status = event.content.status;
        if (event.content.priority !== undefined) priority = event.content.priority;
        if (event.content.assignee !== undefined) assignee = event.content.assignee;
        if (event.content.parentId !== undefined) parentId = event.content.parentId;
        if (event.content.tags !== undefined) tags = event.content.tags;
        break;

      // Comment and blockage events are metadata-only — skip them
      case "comment":
      case "comment-update":
      case "comment-delete":
      case "blockage-added":
      case "blockage-resolved":
      case "blockage-deleted":
        break;
    }
  }

  return {
    id: issueId,
    title,
    description,
    status,
    priority,
    assignee,
    parentId,
    tags,
    createdAt,
    createdBy,
    updatedAt,
  };
}

import { join } from "node:path";
import type { IndexEntry, IndexFile, IssueId } from "../types";
import { atomicWriteJSON, readJSON } from "./file-io";

const INDEX_FILE = "index.json";

/**
 * Read the index file from the tracker directory.
 */
export async function readIndex(trackerDir: string): Promise<IndexFile> {
  return readJSON<IndexFile>(join(trackerDir, INDEX_FILE));
}

/**
 * Write the index file to the tracker directory atomically.
 */
export async function writeIndex(trackerDir: string, index: IndexFile): Promise<void> {
  await atomicWriteJSON(join(trackerDir, INDEX_FILE), index);
}

/**
 * Binary search for an entry by id in a sorted array.
 * Returns the index of the entry, or -1 if not found.
 */
function binarySearchIndex(entries: IndexEntry[], id: IssueId): number {
  let lo = 0;
  let hi = entries.length - 1;

  while (lo <= hi) {
    const mid = (lo + hi) >>> 1;
    const cmp = entries[mid].id.localeCompare(id);
    if (cmp === 0) return mid;
    if (cmp < 0) lo = mid + 1;
    else hi = mid - 1;
  }

  return -1;
}

/**
 * Insert entry into the correct array (open or closed) maintaining sort by id.
 * Returns a new IndexFile (immutable — original is not mutated).
 */
export function insertEntry(index: IndexFile, entry: IndexEntry): IndexFile {
  const isOpen = entry.status !== "closed";
  const arr = isOpen ? index.open : index.closed;

  // Find insertion point via binary search
  let lo = 0;
  let hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >>> 1;
    if (arr[mid].id.localeCompare(entry.id) < 0) lo = mid + 1;
    else hi = mid;
  }

  const newArr = [...arr.slice(0, lo), entry, ...arr.slice(lo)];

  // Update childrenOf if entry has a parentId
  const childrenOf = { ...index.childrenOf };
  if (entry.parentId) {
    childrenOf[entry.parentId] = [...(childrenOf[entry.parentId] ?? []), entry.id];
  }

  return isOpen
    ? { ...index, open: newArr, childrenOf }
    : { ...index, closed: newArr, childrenOf };
}

/**
 * Update an existing entry (find by id, replace).
 * Handles open <-> closed array moves if status changed.
 * Returns a new IndexFile (immutable — original is not mutated).
 */
export function updateEntry(
  index: IndexFile,
  id: IssueId,
  updates: Partial<IndexEntry>,
): IndexFile {
  // Try to find in open array
  const openIdx = binarySearchIndex(index.open, id);
  if (openIdx !== -1) {
    const oldEntry = index.open[openIdx];
    const newEntry = { ...oldEntry, ...updates };

    // If status changed to closed, move to closed array
    if (newEntry.status === "closed") {
      const newOpen = [...index.open.slice(0, openIdx), ...index.open.slice(openIdx + 1)];
      return insertEntry({ ...index, open: newOpen }, newEntry);
    }

    // Stay in open — update in place
    const newOpen = [...index.open];
    newOpen[openIdx] = newEntry;
    return { ...index, open: newOpen };
  }

  // Try to find in closed array
  const closedIdx = binarySearchIndex(index.closed, id);
  if (closedIdx !== -1) {
    const oldEntry = index.closed[closedIdx];
    const newEntry = { ...oldEntry, ...updates };

    // If status changed from closed to open, move to open array
    if (newEntry.status !== "closed") {
      const newClosed = [...index.closed.slice(0, closedIdx), ...index.closed.slice(closedIdx + 1)];
      return insertEntry({ ...index, closed: newClosed }, newEntry);
    }

    // Stay in closed — update in place
    const newClosed = [...index.closed];
    newClosed[closedIdx] = newEntry;
    return { ...index, closed: newClosed };
  }

  // Entry not found — return unchanged
  return index;
}

/**
 * Binary search by id in both open and closed arrays.
 * Returns null if not found.
 */
export function findEntry(index: IndexFile, id: IssueId): IndexEntry | null {
  const openIdx = binarySearchIndex(index.open, id);
  if (openIdx !== -1) return index.open[openIdx];

  const closedIdx = binarySearchIndex(index.closed, id);
  if (closedIdx !== -1) return index.closed[closedIdx];

  return null;
}

/**
 * Remove entry from whichever array it's in.
 * Returns unchanged index if not found.
 * Returns a new IndexFile (immutable — original is not mutated).
 */
export function removeEntry(index: IndexFile, id: IssueId): IndexFile {
  const openIdx = binarySearchIndex(index.open, id);
  if (openIdx !== -1) {
    return { ...index, open: [...index.open.slice(0, openIdx), ...index.open.slice(openIdx + 1)] };
  }

  const closedIdx = binarySearchIndex(index.closed, id);
  if (closedIdx !== -1) {
    return {
      ...index,
      closed: [...index.closed.slice(0, closedIdx), ...index.closed.slice(closedIdx + 1)],
    };
  }

  return index;
}

import { existsSync, mkdirSync } from "node:fs";
import { join, resolve } from "node:path";
import type {
  ConfigFile,
  CreateParams,
  CreateResult,
  DependenciesFile,
  HistoryResult,
  IndexEntry,
  IndexFile,
  InitResult,
  IssueId,
  IssueStatus,
  ListParams,
  ListResult,
  UpdateParams,
  UpdateResult,
  UsersFile,
  ViewResult,
} from "../types";
import { ErrorCodes, TrackgenticError } from "./errors";
import { appendEvent, computeState, replayEvents } from "./events";
import { atomicWriteJSON } from "./file-io";
import { generateId } from "./id";
import { findEntry, insertEntry, readIndex, updateEntry, writeIndex } from "./index-manager";
import { resolveTrackerDir } from "./resolution";

const TRACKGENTIC_DIR = ".trackgentic";

/**
 * Default config.json contents.
 */
const DEFAULT_CONFIG: ConfigFile = {
  auth: {
    mode: "read-only",
    defaultUser: "anonymous",
  },
};

/**
 * Default index.json contents.
 */
const DEFAULT_INDEX: IndexFile = {
  open: [],
  closed: [],
  childrenOf: {},
};

/**
 * Default dependencies.json contents.
 */
const DEFAULT_DEPENDENCIES: DependenciesFile = {
  blockedBy: {},
  blocks: {},
};

/**
 * Default users.json contents.
 */
const DEFAULT_USERS: UsersFile = {
  users: [],
};

/**
 * Tracker — the main programmatic API for trackgentic.
 *
 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
 */
export class Tracker {
  private cwd: string;

  constructor(cwd?: string) {
    this.cwd = cwd ?? process.cwd();
  }

  /**
   * Initialize a new `.trackgentic/` directory in `cwd`.
   *
   * Creates the directory with:
   * - config.json — default auth config
   * - index.json — empty open/closed arrays, empty childrenOf map
   * - dependencies.json — empty blockedBy/blocks maps
   * - users.json — empty users array
   * - issues/ — empty directory
   *
   * Idempotent: if `.trackgentic/` already exists, returns ALREADY_INITIALIZED
   * without overwriting any files.
   */
  async init(): Promise<InitResult> {
    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);

    if (existsSync(trackerDir)) {
      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
    }

    // Create the main directory
    mkdirSync(trackerDir, { recursive: true });

    // Create issues subdirectory
    mkdirSync(join(trackerDir, "issues"), { recursive: true });

    // Write initial files
    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);

    return { result: "OK", path: resolve(trackerDir) };
  }

  /**
   * Create a new issue.
   */
  async create(params: CreateParams): Promise<CreateResult> {
    const trackerDir = resolveTrackerDir(this.cwd);
    if (!trackerDir) {
      throw new TrackgenticError(
        ErrorCodes.NOT_INITIALIZED.result,
        "No .trackgentic/ directory found. Run `trackgentic init` first.",
        ErrorCodes.NOT_INITIALIZED.exitCode,
      );
    }

    const id = generateId();
    const issuePath = params.path ?? `issues/${id}.json`;
    const author = params.author ?? "anonymous";
    const now = new Date().toISOString();

    const title = params.title;
    const description = params.description ?? "";
    const status: IssueStatus = params.status ?? "idea";
    const priority = params.priority ?? 3;
    const assignee = params.assignee ?? null;
    const parentId = params.parentId ?? null;
    const tags = params.tags ?? [];

    // Create issue file with two events: creation + update
    const creationEvent = { type: "creation" as const, timestamp: now, author };
    const updateContent: Record<string, unknown> = { title };
    if (description) updateContent.description = description;
    if (status !== "idea") updateContent.status = status;
    if (priority !== 3) updateContent.priority = priority;
    if (assignee !== null) updateContent.assignee = assignee;
    if (parentId !== null) updateContent.parentId = parentId;
    if (tags.length > 0) updateContent.tags = tags;

    const updateEvent = {
      type: "update" as const,
      timestamp: now,
      author,
      content: updateContent,
    };

    // Write the issue file
    const issueFilePath = join(trackerDir, issuePath);
    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);

    // Build index entry and insert into index
    const entry: IndexEntry = {
      id,
      title,
      path: issuePath,
      status,
      assignee,
      parentId,
      tags,
      priority,
    };

    const index = await readIndex(trackerDir);
    const updatedIndex = insertEntry(index, entry);
    await writeIndex(trackerDir, updatedIndex);

    return { id };
  }

  /**
   * List issues from the index, with optional filters.
   */
  async list(params?: ListParams): Promise<ListResult> {
    const trackerDir = resolveTrackerDir(this.cwd);
    if (!trackerDir) {
      throw new TrackgenticError(
        ErrorCodes.NOT_INITIALIZED.result,
        "No .trackgentic/ directory found. Run `trackgentic init` first.",
        ErrorCodes.NOT_INITIALIZED.exitCode,
      );
    }

    const index = await readIndex(trackerDir);

    // Determine source arrays based on params.status
    let entries: IndexEntry[];
    if (params?.status === "closed") {
      entries = index.closed;
    } else if (params?.status === "open") {
      entries = index.open;
    } else if (params?.status) {
      // Specific non-closed status — search open array
      entries = index.open;
    } else {
      // No status filter — both arrays
      entries = [...index.open, ...index.closed];
    }

    // Filter in memory
    let filtered = entries;

    if (params?.status && params.status !== "open" && params.status !== "closed") {
      filtered = filtered.filter((e) => e.status === params.status);
    }

    if (params?.assignee) {
      filtered = filtered.filter((e) => e.assignee === params.assignee);
    }

    if (params?.tags && params.tags.length > 0) {
      filtered = filtered.filter((e) => params.tags!.every((tag) => e.tags.includes(tag)));
    }

    if (params?.parentId !== undefined) {
      if (params.parentId === null) {
        filtered = filtered.filter((e) => e.parentId === null);
      } else {
        filtered = filtered.filter((e) => e.parentId === params.parentId);
      }
    }

    // Sort: priority ASC → id ASC
    filtered.sort((a, b) => {
      if (a.priority !== b.priority) return a.priority - b.priority;
      return a.id.localeCompare(b.id);
    });

    return filtered;
  }

  /**
   * View a single issue's full computed state.
   */
  async view(id: IssueId): Promise<ViewResult> {
    const trackerDir = resolveTrackerDir(this.cwd);
    if (!trackerDir) {
      throw new TrackgenticError(
        ErrorCodes.NOT_INITIALIZED.result,
        "No .trackgentic/ directory found. Run `trackgentic init` first.",
        ErrorCodes.NOT_INITIALIZED.exitCode,
      );
    }

    const index = await readIndex(trackerDir);
    const entry = findEntry(index, id);
    if (!entry) {
      throw new TrackgenticError(
        ErrorCodes.NOT_FOUND.result,
        `Issue ${id} not found in index.`,
        ErrorCodes.NOT_FOUND.exitCode,
      );
    }

    const issueFilePath = join(trackerDir, entry.path);
    if (!existsSync(issueFilePath)) {
      throw new TrackgenticError(
        ErrorCodes.ISSUE_MISSING.result,
        `Issue file for ${id} is missing.`,
        ErrorCodes.ISSUE_MISSING.exitCode,
      );
    }

    const events = await replayEvents(issueFilePath);
    return computeState(events, id);
  }

  /**
   * Update an existing issue.
   */
  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
    const trackerDir = resolveTrackerDir(this.cwd);
    if (!trackerDir) {
      throw new TrackgenticError(
        ErrorCodes.NOT_INITIALIZED.result,
        "No .trackgentic/ directory found. Run `trackgentic init` first.",
        ErrorCodes.NOT_INITIALIZED.exitCode,
      );
    }

    // Validate at least one field provided (besides author)
    const hasField =
      params.title !== undefined ||
      params.description !== undefined ||
      params.status !== undefined ||
      params.assignee !== undefined ||
      params.tags !== undefined ||
      params.priority !== undefined ||
      params.parentId !== undefined;

    if (!hasField) {
      throw new TrackgenticError(
        ErrorCodes.INVALID_PARAMS.result,
        "At least one field must be provided for update.",
        ErrorCodes.INVALID_PARAMS.exitCode,
      );
    }

    const index = await readIndex(trackerDir);
    const entry = findEntry(index, id);
    if (!entry) {
      throw new TrackgenticError(
        ErrorCodes.NOT_FOUND.result,
        `Issue ${id} not found in index.`,
        ErrorCodes.NOT_FOUND.exitCode,
      );
    }

    const issueFilePath = join(trackerDir, entry.path);
    if (!existsSync(issueFilePath)) {
      throw new TrackgenticError(
        ErrorCodes.ISSUE_MISSING.result,
        `Issue file for ${id} is missing.`,
        ErrorCodes.ISSUE_MISSING.exitCode,
      );
    }

    // Build update event content with only the provided fields
    const content: Record<string, unknown> = {};
    if (params.title !== undefined) content.title = params.title;
    if (params.description !== undefined) content.description = params.description;
    if (params.status !== undefined) content.status = params.status;
    if (params.assignee !== undefined) content.assignee = params.assignee;
    if (params.tags !== undefined) content.tags = params.tags;
    if (params.priority !== undefined) content.priority = params.priority;
    if (params.parentId !== undefined) content.parentId = params.parentId;

    const author = params.author ?? "anonymous";
    const now = new Date().toISOString();

    const updateEvent = {
      type: "update" as const,
      timestamp: now,
      author,
      content,
    };

    // Append event to issue file
    await appendEvent(issueFilePath, updateEvent);

    // Recompute state from all events
    const events = await replayEvents(issueFilePath);
    const computed = computeState(events, id);

    // Update index entry with new computed values
    const updatedIndex = updateEntry(index, id, {
      title: computed.title,
      status: computed.status,
      assignee: computed.assignee,
      parentId: computed.parentId,
      tags: computed.tags,
      priority: computed.priority,
    });

    await writeIndex(trackerDir, updatedIndex);

    return { result: "OK" };
  }

  /**
   * Get the raw event history for an issue.
   */
  async history(id: IssueId): Promise<HistoryResult> {
    const trackerDir = resolveTrackerDir(this.cwd);
    if (!trackerDir) {
      throw new TrackgenticError(
        ErrorCodes.NOT_INITIALIZED.result,
        "No .trackgentic/ directory found. Run `trackgentic init` first.",
        ErrorCodes.NOT_INITIALIZED.exitCode,
      );
    }

    const index = await readIndex(trackerDir);
    const entry = findEntry(index, id);
    if (!entry) {
      throw new TrackgenticError(
        ErrorCodes.NOT_FOUND.result,
        `Issue ${id} not found in index.`,
        ErrorCodes.NOT_FOUND.exitCode,
      );
    }

    const issueFilePath = join(trackerDir, entry.path);
    if (!existsSync(issueFilePath)) {
      throw new TrackgenticError(
        ErrorCodes.ISSUE_MISSING.result,
        `Issue file for ${id} is missing.`,
        ErrorCodes.ISSUE_MISSING.exitCode,
      );
    }

    return replayEvents(issueFilePath);
  }
}

import { TrackgenticError } from "../../core/errors";
import { Tracker } from "../../core/tracker";
import { writeStderr, writeStdout } from "../output";

/**
 * Handler for the `trackgentic create <title>` command.
 */
export async function createAction(title: string, options: Record<string, unknown>): Promise<void> {
  try {
    const tracker = new Tracker();
    const result = await tracker.create({
      title,
      description: options.description as string | undefined,
      assignee: options.assignee as string | undefined,
      tags: options.tags ? (options.tags as string).split(",").map((t: string) => t.trim()) : undefined,
      status: options.status as string | undefined,
      priority: options.priority ? Number.parseInt(options.priority as string, 10) as 1 | 2 | 3 | 4 | 5 : undefined,
      parentId: options.parentId as string | undefined,
      path: options.path as string | undefined,
    });
    writeStdout(result);
    process.exit(0);
  } catch (err) {
    if (err instanceof TrackgenticError) {
      writeStderr({ result: err.result, message: err.message });
      process.exit(err.exitCode);
    }
    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
    process.exit(1);
  }
}

