import { Command } from "commander";
import { createAction } from "./commands/create";
import { historyAction } from "./commands/history";
import { initAction } from "./commands/init";
import { listAction } from "./commands/list";
import { updateAction } from "./commands/update";
import { viewAction } from "./commands/view";

/**
 * Create and configure the Commander program.
 */
export function createProgram(): Command {
  const program = new Command();

  program
    .name("trackgentic")
    .description("Issue tracker designed for AI agents — file-backed, event-sourced, git-friendly")
    .version("0.1.0");

  // ─── init ─────────────────────────────────────────────────────────
  program
    .command("init")
    .description("Initialize a new .trackgentic/ directory")
    .action(initAction);

  // ─── create ───────────────────────────────────────────────────────
  program
    .command("create <title>")
    .description("Create a new issue")
    .option("--description <string>", "Issue description")
    .option("--assignee <string>", "Assignee name")
    .option("--tags <comma-separated>", "Comma-separated tags")
    .option("--status <status>", 'Issue status (default: "idea")')
    .option("--priority <number>", "Priority 1-5 (default: 3)")
    .option("--parentId <id>", "Parent issue ID")
    .option("--path <string>", "Custom file path for the issue")
    .action(createAction);

  // ─── list ─────────────────────────────────────────────────────────
  program
    .command("list")
    .description("List issues")
    .option("--status <status>", 'Filter by status (use "open" for non-closed, "closed" for closed)')
    .option("--assignee <string>", "Filter by assignee")
    .option("--tags <comma-separated>", "Comma-separated tags (AND filter)")
    .option("--parentId <id>", 'Filter by parent ID (use "null" for top-level)')
    .action(listAction);

  // ─── view ─────────────────────────────────────────────────────────
  program
    .command("view <issueId>")
    .description("View an issue's full computed state")
    .action(viewAction);

  // ─── update ───────────────────────────────────────────────────────
  program
    .command("update <issueId>")
    .description("Update an existing issue")
    .option("--title <string>", "New title")
    .option("--description <string>", "New description")
    .option("--status <status>", "New status")
    .option("--assignee <string>", "New assignee")
    .option("--tags <comma-separated>", "New tags (replaces existing)")
    .option("--priority <number>", "New priority (1-5)")
    .option('--parentId <id>', 'New parent ID (use "null" to detach)')
    .action(updateAction);

  // ─── history ──────────────────────────────────────────────────────
  program
    .command("history <issueId>")
    .description("View an issue's raw event history")
    .action(historyAction);

  return program;
}

import { afterEach, beforeEach, describe, expect, test } from "bun:test";
import { existsSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { appendEvent, computeState, replayEvents } from "../../src/core/events";
import type { Event } from "../../src/types";

describe("Event Engine", () => {
  let testDir: string;

  beforeEach(() => {
    testDir = join(
      tmpdir(),
      `trackgentic-events-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    );
  });

  afterEach(() => {
    rmSync(testDir, { recursive: true, force: true });
  });

  describe("computeState", () => {
    test("with creation event only → defaults + id, createdAt, createdBy", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
      ];

      const result = computeState(events, "abc123def4");

      expect(result.id).toBe("abc123def4");
      expect(result.createdAt).toBe("2026-01-01T00:00:00.000Z");
      expect(result.createdBy).toBe("alice");
      expect(result.updatedAt).toBe("2026-01-01T00:00:00.000Z");
      expect(result.title).toBe("");
      expect(result.description).toBe("");
      expect(result.status).toBe("idea");
      expect(result.priority).toBe(3);
      expect(result.assignee).toBeNull();
      expect(result.parentId).toBeNull();
      expect(result.tags).toEqual([]);
    });

    test("with creation + update → properties applied", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "bob",
          content: {
            title: "My Issue",
            description: "Some details",
            status: "todo",
            priority: 1,
            assignee: "bob",
            tags: ["bug", "urgent"],
          },
        },
      ];

      const result = computeState(events, "abc123def4");

      expect(result.title).toBe("My Issue");
      expect(result.description).toBe("Some details");
      expect(result.status).toBe("todo");
      expect(result.priority).toBe(1);
      expect(result.assignee).toBe("bob");
      expect(result.tags).toEqual(["bug", "urgent"]);
      expect(result.updatedAt).toBe("2026-01-01T01:00:00.000Z");
      expect(result.createdAt).toBe("2026-01-01T00:00:00.000Z");
      expect(result.createdBy).toBe("alice");
    });

    test("with multiple updates → last value wins for each field", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "bob",
          content: { title: "First Title", status: "todo" },
        },
        {
          type: "update",
          timestamp: "2026-01-01T02:00:00.000Z",
          author: "charlie",
          content: { title: "Second Title", priority: 5 },
        },
      ];

      const result = computeState(events, "abc123def4");

      expect(result.title).toBe("Second Title");
      expect(result.status).toBe("todo"); // Not updated in second event, persists
      expect(result.priority).toBe(5);
      expect(result.updatedAt).toBe("2026-01-01T02:00:00.000Z");
    });

    test("ignores comment events", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "alice",
          content: { title: "Test" },
        },
        {
          type: "comment",
          timestamp: "2026-01-01T02:00:00.000Z",
          author: "bob",
          content: { id: "cmt1234567", content: "A comment" },
        },
      ];

      const result = computeState(events, "abc123def4");

      expect(result.title).toBe("Test");
      expect(result.updatedAt).toBe("2026-01-01T02:00:00.000Z"); // updatedAt reflects last event
    });

    test("ignores blockage events", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "alice",
          content: { title: "Test" },
        },
        {
          type: "blockage-added",
          timestamp: "2026-01-01T02:00:00.000Z",
          author: "alice",
          content: { blockerId: "xyz987abcd" },
        },
      ];

      const result = computeState(events, "abc123def4");

      expect(result.title).toBe("Test");
      expect(result.updatedAt).toBe("2026-01-01T02:00:00.000Z");
    });

    test("handles parentId in update event", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "alice",
          content: { title: "Child", parentId: "parent123i" },
        },
      ];

      const result = computeState(events, "child12345");

      expect(result.parentId).toBe("parent123i");
    });

    test("handles assignee set to null", () => {
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "alice",
          content: { title: "Test", assignee: "bob" },
        },
        {
          type: "update",
          timestamp: "2026-01-01T02:00:00.000Z",
          author: "alice",
          content: { assignee: null },
        },
      ];

      const result = computeState(events, "abc123def4");

      expect(result.assignee).toBeNull();
    });
  });

  describe("appendEvent", () => {
    test("creates valid JSON array when file doesn't exist", async () => {
      const filePath = join(testDir, "test-issue.json");
      const event: Event = {
        type: "creation",
        timestamp: "2026-01-01T00:00:00.000Z",
        author: "alice",
      };

      await appendEvent(filePath, event);

      expect(existsSync(filePath)).toBe(true);
      const contents = JSON.parse(await import("node:fs/promises").readFile(filePath, "utf-8"));
      expect(Array.isArray(contents)).toBe(true);
      expect(contents).toHaveLength(1);
      expect(contents[0]).toEqual(event);
    });

    test("appends to existing file", async () => {
      const filePath = join(testDir, "test-issue.json");

      const event1: Event = {
        type: "creation",
        timestamp: "2026-01-01T00:00:00.000Z",
        author: "alice",
      };
      const event2: Event = {
        type: "update",
        timestamp: "2026-01-01T01:00:00.000Z",
        author: "bob",
        content: { title: "Test" },
      };

      await appendEvent(filePath, event1);
      await appendEvent(filePath, event2);

      const contents = JSON.parse(await import("node:fs/promises").readFile(filePath, "utf-8"));
      expect(contents).toHaveLength(2);
      expect(contents[0]).toEqual(event1);
      expect(contents[1]).toEqual(event2);
    });

    test("appends to existing array in file", async () => {
      const filePath = join(testDir, "test-issue.json");
      const existingEvent: Event = {
        type: "creation",
        timestamp: "2026-01-01T00:00:00.000Z",
        author: "alice",
      };

      writeFileSync(filePath, JSON.stringify([existingEvent], null, 2));

      const newEvent: Event = {
        type: "update",
        timestamp: "2026-01-01T01:00:00.000Z",
        author: "bob",
        content: { title: "Updated" },
      };

      await appendEvent(filePath, newEvent);

      const contents = JSON.parse(await import("node:fs/promises").readFile(filePath, "utf-8"));
      expect(contents).toHaveLength(2);
    });
  });

  describe("replayEvents", () => {
    test("returns events in order", async () => {
      const filePath = join(testDir, "test-issue.json");
      const events: Event[] = [
        { type: "creation", timestamp: "2026-01-01T00:00:00.000Z", author: "alice" },
        {
          type: "update",
          timestamp: "2026-01-01T01:00:00.000Z",
          author: "bob",
          content: { title: "Test" },
        },
      ];

      writeFileSync(filePath, JSON.stringify(events, null, 2));

      const result = await replayEvents(filePath);

      expect(result).toHaveLength(2);
      expect(result[0].type).toBe("creation");
      expect(result[1].type).toBe("update");
    });

    test("returns empty array for file with empty array", async () => {
      const filePath = join(testDir, "test-issue.json");
      writeFileSync(filePath, "[]");

      const result = await replayEvents(filePath);

      expect(result).toEqual([]);
    });
  });
});

import { describe, expect, test } from "bun:test";
import type { IndexEntry, IndexFile } from "../../src/types";
import {
  findEntry,
  insertEntry,
  removeEntry,
  updateEntry,
} from "../../src/core/index-manager";

const EMPTY_INDEX: IndexFile = {
  open: [],
  closed: [],
  childrenOf: {},
};

function makeEntry(overrides: Partial<IndexEntry> = {}): IndexEntry {
  return {
    id: "abc123test",
    title: "Test Issue",
    path: "issues/abc123test.json",
    status: "idea",
    assignee: null,
    parentId: null,
    tags: [],
    priority: 3,
    ...overrides,
  };
}

describe("Index Manager", () => {
  describe("insertEntry", () => {
    test("inserts into empty index", () => {
      const entry = makeEntry({ id: "aaa111first" });
      const result = insertEntry(EMPTY_INDEX, entry);

      expect(result.open).toHaveLength(1);
      expect(result.open[0].id).toBe("aaa111first");
      expect(result.closed).toHaveLength(0);
    });

    test("maintains sort order by id", () => {
      const entry1 = makeEntry({ id: "zzz999last" });
      const entry2 = makeEntry({ id: "aaa111first" });
      const entry3 = makeEntry({ id: "mmm555midd" });

      let index = insertEntry(EMPTY_INDEX, entry1);
      index = insertEntry(index, entry2);
      index = insertEntry(index, entry3);

      expect(index.open).toHaveLength(3);
      expect(index.open[0].id).toBe("aaa111first");
      expect(index.open[1].id).toBe("mmm555midd");
      expect(index.open[2].id).toBe("zzz999last");
    });

    test("puts closed status in closed array", () => {
      const entry = makeEntry({ id: "cls1234567", status: "closed" });
      const result = insertEntry(EMPTY_INDEX, entry);

      expect(result.open).toHaveLength(0);
      expect(result.closed).toHaveLength(1);
      expect(result.closed[0].id).toBe("cls1234567");
    });

    test("puts different statuses in open array", () => {
      for (const status of ["idea", "todo", "in-progress", "done"] as const) {
        const entry = makeEntry({ id: `tst${status}`, status });
        const result = insertEntry(EMPTY_INDEX, entry);
        expect(result.open).toHaveLength(1);
        expect(result.closed).toHaveLength(0);
      }
    });

    test("updates childrenOf when parentId is set", () => {
      const entry = makeEntry({ id: "child12345", parentId: "parent1234" });
      const result = insertEntry(EMPTY_INDEX, entry);

      expect(result.childrenOf["parent1234"]).toEqual(["child12345"]);
    });

    test("does not add childrenOf key when parentId is null", () => {
      const entry = makeEntry({ id: "orphan12345", parentId: null });
      const result = insertEntry(EMPTY_INDEX, entry);

      expect(Object.keys(result.childrenOf)).toHaveLength(0);
    });
  });

  describe("findEntry", () => {
    test("finds existing entry in open array", () => {
      const entry = makeEntry({ id: "findme1234" });
      const index = insertEntry(EMPTY_INDEX, entry);

      const found = findEntry(index, "findme1234");

      expect(found).not.toBeNull();
      expect(found?.id).toBe("findme1234");
    });

    test("finds existing entry in closed array", () => {
      const entry = makeEntry({ id: "closed12345", status: "closed" });
      const index = insertEntry(EMPTY_INDEX, entry);

      const found = findEntry(index, "closed12345");

      expect(found).not.toBeNull();
      expect(found?.id).toBe("closed12345");
    });

    test("returns null for missing entry", () => {
      const entry = makeEntry({ id: "exists12345" });
      const index = insertEntry(EMPTY_INDEX, entry);

      const found = findEntry(index, "missing12345");

      expect(found).toBeNull();
    });

    test("returns null for empty index", () => {
      const found = findEntry(EMPTY_INDEX, "anything123");

      expect(found).toBeNull();
    });

    test("uses binary search — finds entry in large array", () => {
      let index = EMPTY_INDEX;
      for (let i = 0; i < 1000; i++) {
        const id = i.toString(36).padStart(10, "0");
        index = insertEntry(index, makeEntry({ id, title: `Issue ${i}` }));
      }

      // Find a specific entry
      const found = findEntry(index, "0000000037"); // 37 in base36, padded
      // Note: the actual ID format depends on padStart behavior
      // Let's just verify findEntry works on a known ID
      const midEntry = index.open[500];
      const found2 = findEntry(index, midEntry.id);

      expect(found2).not.toBeNull();
      expect(found2?.id).toBe(midEntry.id);
    });
  });

  describe("updateEntry", () => {
    test("changes fields in place", () => {
      const entry = makeEntry({ id: "update12345", title: "Original" });
      let index = insertEntry(EMPTY_INDEX, entry);

      index = updateEntry(index, "update12345", { title: "Updated" });

      const found = findEntry(index, "update12345");
      expect(found?.title).toBe("Updated");
    });

    test("moves from open to closed on status change", () => {
      const entry = makeEntry({ id: "move1234567", status: "todo" });
      let index = insertEntry(EMPTY_INDEX, entry);

      expect(index.open).toHaveLength(1);
      expect(index.closed).toHaveLength(0);

      index = updateEntry(index, "move1234567", { status: "closed" });

      expect(index.open).toHaveLength(0);
      expect(index.closed).toHaveLength(1);
      expect(index.closed[0].id).toBe("move1234567");
      expect(index.closed[0].status).toBe("closed");
    });

    test("moves from closed to open on status change", () => {
      const entry = makeEntry({ id: "reopen123456", status: "closed" });
      let index = insertEntry(EMPTY_INDEX, entry);

      expect(index.open).toHaveLength(0);
      expect(index.closed).toHaveLength(1);

      index = updateEntry(index, "reopen123456", { status: "todo" });

      expect(index.open).toHaveLength(1);
      expect(index.closed).toHaveLength(0);
      expect(index.open[0].id).toBe("reopen123456");
      expect(index.open[0].status).toBe("todo");
    });

    test("returns unchanged index if id not found", () => {
      const entry = makeEntry({ id: "exists12345" });
      const index = insertEntry(EMPTY_INDEX, entry);

      const result = updateEntry(index, "missing12345", { title: "New" });

      expect(result).toBe(index);
    });

    test("maintains sort order after move", () => {
      const entry1 = makeEntry({ id: "aaa11111111", status: "todo" });
      const entry2 = makeEntry({ id: "bbb22222222", status: "todo" });
      const entry3 = makeEntry({ id: "ccc33333333", status: "todo" });

      let index = EMPTY_INDEX;
      index = insertEntry(index, entry3);
      index = insertEntry(index, entry1);
      index = insertEntry(index, entry2);

      // Close the middle entry
      index = updateEntry(index, "bbb22222222", { status: "closed" });

      // Open array should have 2, sorted
      expect(index.open).toHaveLength(2);
      expect(index.open[0].id).toBe("aaa11111111");
      expect(index.open[1].id).toBe("ccc33333333");

      // Closed array should have 1
      expect(index.closed).toHaveLength(1);
      expect(index.closed[0].id).toBe("bbb22222222");
    });
  });

  describe("removeEntry", () => {
    test("removes from open array", () => {
      const entry = makeEntry({ id: "remove12345" });
      let index = insertEntry(EMPTY_INDEX, entry);

      expect(index.open).toHaveLength(1);

      index = removeEntry(index, "remove12345");

      expect(index.open).toHaveLength(0);
    });

    test("removes from closed array", () => {
      const entry = makeEntry({ id: "remove12345", status: "closed" });
      let index = insertEntry(EMPTY_INDEX, entry);

      expect(index.closed).toHaveLength(1);

      index = removeEntry(index, "remove12345");

      expect(index.closed).toHaveLength(0);
    });

    test("returns unchanged index if id not found", () => {
      const entry = makeEntry({ id: "exists12345" });
      const index = insertEntry(EMPTY_INDEX, entry);

      const result = removeEntry(index, "missing12345");

      expect(result).toBe(index);
    });

    test("removes from correct array when both have entries", () => {
      const openEntry = makeEntry({ id: "open1234567" });
      const closedEntry = makeEntry({ id: "closed123456", status: "closed" });
      let index = insertEntry(EMPTY_INDEX, openEntry);
      index = insertEntry(index, closedEntry);

      index = removeEntry(index, "open1234567");

      expect(index.open).toHaveLength(0);
      expect(index.closed).toHaveLength(1);
      expect(index.closed[0].id).toBe("closed123456");
    });
  });
});

import { afterEach, beforeEach, describe, expect, test } from "bun:test";
import { existsSync, readFileSync, rmSync, unlinkSync } from "node:fs";
import { tmpdir } from "node:os";
import { join, resolve } from "node:path";
import { Tracker } from "../../src/core/tracker";
import { TrackgenticError } from "../../src/core/errors";

describe("Tracker", () => {
  let testDir: string;

  beforeEach(() => {
    testDir = join(
      tmpdir(),
      `trackgentic-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    );
  });

  afterEach(() => {
    rmSync(testDir, { recursive: true, force: true });
  });

  describe("init()", () => {
    test("creates .trackgentic/ with all files and correct contents", async () => {
      const tracker = new Tracker(testDir);
      const result = await tracker.init();

      expect(result.result).toBe("OK");
      expect(result.path).toBe(resolve(join(testDir, ".trackgentic")));

      // Verify directory exists
      expect(existsSync(join(testDir, ".trackgentic"))).toBe(true);

      // Verify issues directory exists
      expect(existsSync(join(testDir, ".trackgentic", "issues"))).toBe(true);

      // Verify config.json
      const config = JSON.parse(
        readFileSync(join(testDir, ".trackgentic", "config.json"), "utf-8"),
      );
      expect(config).toEqual({
        auth: {
          mode: "read-only",
          defaultUser: "anonymous",
        },
      });

      // Verify index.json
      const index = JSON.parse(readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"));
      expect(index).toEqual({
        open: [],
        closed: [],
        childrenOf: {},
      });

      // Verify dependencies.json
      const deps = JSON.parse(
        readFileSync(join(testDir, ".trackgentic", "dependencies.json"), "utf-8"),
      );
      expect(deps).toEqual({
        blockedBy: {},
        blocks: {},
      });

      // Verify users.json
      const users = JSON.parse(readFileSync(join(testDir, ".trackgentic", "users.json"), "utf-8"));
      expect(users).toEqual({
        users: [],
      });
    });

    test("is idempotent — second call returns ALREADY_INITIALIZED", async () => {
      const tracker = new Tracker(testDir);

      const first = await tracker.init();
      expect(first.result).toBe("OK");

      const second = await tracker.init();
      expect(second.result).toBe("ALREADY_INITIALIZED");
      expect(second.path).toBe(resolve(join(testDir, ".trackgentic")));
    });

    test("does not overwrite existing files", async () => {
      const tracker = new Tracker(testDir);

      await tracker.init();

      // Read config to get original content
      const configPath = join(testDir, ".trackgentic", "config.json");
      const originalContent = readFileSync(configPath, "utf-8");

      // Call init again
      await tracker.init();

      // Verify config was NOT overwritten
      const contentAfter = readFileSync(configPath, "utf-8");
      expect(contentAfter).toBe(originalContent);
    });

    test("config.json has default auth config", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      const config = JSON.parse(
        readFileSync(join(testDir, ".trackgentic", "config.json"), "utf-8"),
      );
      expect(config.auth.mode).toBe("read-only");
      expect(config.auth.defaultUser).toBe("anonymous");
    });

    test("index.json has empty arrays", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      const index = JSON.parse(readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"));
      expect(index.open).toEqual([]);
      expect(index.closed).toEqual([]);
      expect(index.childrenOf).toEqual({});
    });

    test("issues/ directory exists", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      expect(existsSync(join(testDir, ".trackgentic", "issues"))).toBe(true);
    });
  });

  describe("create()", () => {
    let tracker: Tracker;

    beforeEach(async () => {
      tracker = new Tracker(testDir);
      await tracker.init();
    });

    test("creates an issue with title only", async () => {
      const result = await tracker.create({ title: "Test Issue" });

      expect(result.result).not.toBe("undefined");
      if ("id" in result) {
        expect(result.id).toHaveLength(10);
      }
    });

    test("creates issue file with creation + update events", async () => {
      const result = await tracker.create({ title: "Test Issue" });

      if ("id" in result) {
        const issuePath = join(testDir, ".trackgentic", "issues", `${result.id}.json`);
        expect(existsSync(issuePath)).toBe(true);

        const events = JSON.parse(readFileSync(issuePath, "utf-8"));
        expect(events).toHaveLength(2);
        expect(events[0].type).toBe("creation");
        expect(events[1].type).toBe("update");
        expect(events[1].content.title).toBe("Test Issue");
      }
    });

    test("inserts entry into index", async () => {
      const result = await tracker.create({ title: "Test Issue" });

      if ("id" in result) {
        const index = JSON.parse(
          readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"),
        );
        expect(index.open).toHaveLength(1);
        expect(index.open[0].id).toBe(result.id);
        expect(index.open[0].title).toBe("Test Issue");
      }
    });

    test("creates issue with all properties", async () => {
      const result = await tracker.create({
        title: "Full Issue",
        description: "A description",
        status: "todo",
        priority: 1,
        assignee: "bob",
        tags: ["bug", "urgent"],
        parentId: "parent12345",
      });

      if ("id" in result) {
        const index = JSON.parse(
          readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"),
        );
        const entry = index.open[0];
        expect(entry.title).toBe("Full Issue");
        expect(entry.status).toBe("todo");
        expect(entry.priority).toBe(1);
        expect(entry.assignee).toBe("bob");
        expect(entry.tags).toEqual(["bug", "urgent"]);
        expect(entry.parentId).toBe("parent12345");
      }
    });

    test("creates with closed status goes to closed array", async () => {
      const result = await tracker.create({
        title: "Pre-closed",
        status: "closed",
      });

      if ("id" in result) {
        const index = JSON.parse(
          readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"),
        );
        expect(index.open).toHaveLength(0);
        expect(index.closed).toHaveLength(1);
        expect(index.closed[0].id).toBe(result.id);
      }
    });

    test("throws NOT_INITIALIZED when no .trackgentic/ exists", async () => {
      const uninitTracker = new Tracker(join(testDir, "nonexistent"));
      expect(uninitTracker.create({ title: "Test" })).rejects.toThrow(TrackgenticError);
    });

    test("uses author from params", async () => {
      const result = await tracker.create({ title: "Authored", author: "alice" });

      if ("id" in result) {
        const issuePath = join(testDir, ".trackgentic", "issues", `${result.id}.json`);
        const events = JSON.parse(readFileSync(issuePath, "utf-8"));
        expect(events[0].author).toBe("alice");
        expect(events[1].author).toBe("alice");
      }
    });

    test("uses anonymous as default author", async () => {
      const result = await tracker.create({ title: "Default Authored" });

      if ("id" in result) {
        const issuePath = join(testDir, ".trackgentic", "issues", `${result.id}.json`);
        const events = JSON.parse(readFileSync(issuePath, "utf-8"));
        expect(events[0].author).toBe("anonymous");
      }
    });
  });

  describe("list()", () => {
    let tracker: Tracker;

    beforeEach(async () => {
      tracker = new Tracker(testDir);
      await tracker.init();
    });

    test("returns empty array when no issues", async () => {
      const result = await tracker.list();
      expect(result).toEqual([]);
    });

    test("returns all issues when no filters", async () => {
      await tracker.create({ title: "Issue 1" });
      await tracker.create({ title: "Issue 2" });

      const result = await tracker.list();
      expect(result).toHaveLength(2);
    });

    test("filters by status=open (excludes closed)", async () => {
      await tracker.create({ title: "Open Issue" });
      await tracker.create({ title: "Closed Issue", status: "closed" });

      const result = await tracker.list({ status: "open" });
      expect(result).toHaveLength(1);
      expect(result[0].title).toBe("Open Issue");
    });

    test("filters by status=closed", async () => {
      await tracker.create({ title: "Open Issue" });
      await tracker.create({ title: "Closed Issue", status: "closed" });

      const result = await tracker.list({ status: "closed" });
      expect(result).toHaveLength(1);
      expect(result[0].title).toBe("Closed Issue");
    });

    test("filters by specific status", async () => {
      await tracker.create({ title: "Idea Issue", status: "idea" });
      await tracker.create({ title: "Todo Issue", status: "todo" });

      const result = await tracker.list({ status: "todo" });
      expect(result).toHaveLength(1);
      expect(result[0].title).toBe("Todo Issue");
    });

    test("filters by assignee", async () => {
      await tracker.create({ title: "Alice's Issue", assignee: "alice" });
      await tracker.create({ title: "Bob's Issue", assignee: "bob" });

      const result = await tracker.list({ assignee: "alice" });
      expect(result).toHaveLength(1);
      expect(result[0].title).toBe("Alice's Issue");
    });

    test("filters by tags (AND filter)", async () => {
      await tracker.create({ title: "Bug", tags: ["bug"] });
      await tracker.create({ title: "Bug + Urgent", tags: ["bug", "urgent"] });
      await tracker.create({ title: "Feature", tags: ["feature"] });

      const result = await tracker.list({ tags: ["bug", "urgent"] });
      expect(result).toHaveLength(1);
      expect(result[0].title).toBe("Bug + Urgent");
    });

    test("filters by parentId=null (top-level only)", async () => {
      const parent = await tracker.create({ title: "Parent" });
      if ("id" in parent) {
        await tracker.create({ title: "Child", parentId: parent.id });
      }

      const result = await tracker.list({ parentId: null });
      expect(result).toHaveLength(1);
      expect(result[0].title).toBe("Parent");
    });

    test("sorts by priority ASC then id ASC", async () => {
      // Create with different priorities — need to control creation order for stable ids
      const r1 = await tracker.create({ title: "High P", priority: 1 });
      const r2 = await tracker.create({ title: "Low P", priority: 5 });
      const r3 = await tracker.create({ title: "Med P", priority: 3 });

      const result = await tracker.list();
      expect(result[0].title).toBe("High P");
      expect(result[1].title).toBe("Med P");
      expect(result[2].title).toBe("Low P");
    });

    test("throws NOT_INITIALIZED when no .trackgentic/ exists", () => {
      const uninitTracker = new Tracker(join(testDir, "nonexistent"));
      expect(uninitTracker.list()).rejects.toThrow(TrackgenticError);
    });
  });

  describe("view()", () => {
    let tracker: Tracker;

    beforeEach(async () => {
      tracker = new Tracker(testDir);
      await tracker.init();
    });

    test("returns computed issue state", async () => {
      const created = await tracker.create({ title: "Test Issue", description: "Details" });

      if ("id" in created) {
        const result = await tracker.view(created.id);

        expect(result.id).toBe(created.id);
        if ("title" in result) {
          expect(result.title).toBe("Test Issue");
          expect(result.description).toBe("Details");
          expect(result.status).toBe("idea");
          expect(result.priority).toBe(3);
          expect(result.assignee).toBeNull();
          expect(result.parentId).toBeNull();
          expect(result.tags).toEqual([]);
          expect(result.createdAt).toBeTruthy();
          expect(result.createdBy).toBe("anonymous");
          expect(result.updatedAt).toBeTruthy();
        }
      }
    });

    test("throws NOT_FOUND for non-existent id", async () => {
      expect(tracker.view("missing12345")).rejects.toThrow(TrackgenticError);
    });

    test("throws ISSUE_MISSING when file is deleted", async () => {
      const created = await tracker.create({ title: "Will be deleted" });

      if ("id" in created) {
        // Manually delete the issue file
        const issuePath = join(testDir, ".trackgentic", "issues", `${created.id}.json`);
        unlinkSync(issuePath);

        expect(tracker.view(created.id)).rejects.toThrow(TrackgenticError);
      }
    });

    test("throws NOT_INITIALIZED when no .trackgentic/ exists", () => {
      const uninitTracker = new Tracker(join(testDir, "nonexistent"));
      expect(uninitTracker.view("abc1234567")).rejects.toThrow(TrackgenticError);
    });
  });

  describe("update()", () => {
    let tracker: Tracker;

    beforeEach(async () => {
      tracker = new Tracker(testDir);
      await tracker.init();
    });

    test("updates title and returns OK", async () => {
      const created = await tracker.create({ title: "Original" });

      if ("id" in created) {
        const result = await tracker.update(created.id, { title: "Updated" });
        expect(result).toEqual({ result: "OK" });

        // Verify via view
        const viewed = await tracker.view(created.id);
        if ("title" in viewed) {
          expect(viewed.title).toBe("Updated");
        }
      }
    });

    test("updates multiple fields at once", async () => {
      const created = await tracker.create({ title: "Original" });

      if ("id" in created) {
        await tracker.update(created.id, {
          title: "Updated",
          status: "in-progress",
          priority: 1,
          assignee: "alice",
          tags: ["urgent"],
        });

        const viewed = await tracker.view(created.id);
        if ("title" in viewed) {
          expect(viewed.title).toBe("Updated");
          expect(viewed.status).toBe("in-progress");
          expect(viewed.priority).toBe(1);
          expect(viewed.assignee).toBe("alice");
          expect(viewed.tags).toEqual(["urgent"]);
        }
      }
    });

    test("appends update event to issue file", async () => {
      const created = await tracker.create({ title: "Original" });

      if ("id" in created) {
        await tracker.update(created.id, { title: "Updated" });

        const issuePath = join(testDir, ".trackgentic", "issues", `${created.id}.json`);
        const events = JSON.parse(readFileSync(issuePath, "utf-8"));
        // creation + initial update + our update = 3 events
        expect(events).toHaveLength(3);
        expect(events[2].type).toBe("update");
        expect(events[2].content.title).toBe("Updated");
      }
    });

    test("moves to closed array on status=closed", async () => {
      const created = await tracker.create({ title: "To Close" });

      if ("id" in created) {
        await tracker.update(created.id, { status: "closed" });

        const index = JSON.parse(
          readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"),
        );
        expect(index.open).toHaveLength(0);
        expect(index.closed).toHaveLength(1);
        expect(index.closed[0].id).toBe(created.id);
      }
    });

    test("moves back to open array on status change from closed", async () => {
      const created = await tracker.create({ title: "Reopen", status: "closed" });

      if ("id" in created) {
        await tracker.update(created.id, { status: "todo" });

        const index = JSON.parse(
          readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"),
        );
        expect(index.open).toHaveLength(1);
        expect(index.closed).toHaveLength(0);
        expect(index.open[0].status).toBe("todo");
      }
    });

    test("throws INVALID_PARAMS when no fields provided", async () => {
      const created = await tracker.create({ title: "Test" });

      if ("id" in created) {
        expect(tracker.update(created.id, {})).rejects.toThrow(TrackgenticError);
      }
    });

    test("throws NOT_FOUND for non-existent id", async () => {
      expect(
        tracker.update("missing12345", { title: "Test" }),
      ).rejects.toThrow(TrackgenticError);
    });

    test("throws ISSUE_MISSING when file is deleted", async () => {
      const created = await tracker.create({ title: "Will be deleted" });

      if ("id" in created) {
        const issuePath = join(testDir, ".trackgentic", "issues", `${created.id}.json`);
        unlinkSync(issuePath);

        expect(
          tracker.update(created.id, { title: "Updated" }),
        ).rejects.toThrow(TrackgenticError);
      }
    });

    test("clears assignee by setting to null", async () => {
      const created = await tracker.create({ title: "Test", assignee: "alice" });

      if ("id" in created) {
        await tracker.update(created.id, { assignee: null });

        const viewed = await tracker.view(created.id);
        if ("assignee" in viewed) {
          expect(viewed.assignee).toBeNull();
        }
      }
    });

    test("clears parentId by setting to null", async () => {
      const created = await tracker.create({ title: "Child", parentId: "parent12345" });

      if ("id" in created) {
        await tracker.update(created.id, { parentId: null });

        const viewed = await tracker.view(created.id);
        if ("parentId" in viewed) {
          expect(viewed.parentId).toBeNull();
        }
      }
    });
  });

  describe("history()", () => {
    let tracker: Tracker;

    beforeEach(async () => {
      tracker = new Tracker(testDir);
      await tracker.init();
    });

    test("returns raw event array", async () => {
      const created = await tracker.create({ title: "Test" });

      if ("id" in created) {
        const result = await tracker.history(created.id);

        expect(Array.isArray(result)).toBe(true);
        if (Array.isArray(result)) {
          expect(result).toHaveLength(2);
          expect(result[0].type).toBe("creation");
          expect(result[1].type).toBe("update");
        }
      }
    });

    test("returns all events after update", async () => {
      const created = await tracker.create({ title: "Test" });

      if ("id" in created) {
        await tracker.update(created.id, { title: "Updated" });

        const result = await tracker.history(created.id);

        if (Array.isArray(result)) {
          expect(result).toHaveLength(3);
          expect(result[2].type).toBe("update");
        }
      }
    });

    test("throws NOT_FOUND for non-existent id", async () => {
      expect(tracker.history("missing12345")).rejects.toThrow(TrackgenticError);
    });

    test("throws ISSUE_MISSING when file is deleted", async () => {
      const created = await tracker.create({ title: "Test" });

      if ("id" in created) {
        const issuePath = join(testDir, ".trackgentic", "issues", `${created.id}.json`);
        unlinkSync(issuePath);

        expect(tracker.history(created.id)).rejects.toThrow(TrackgenticError);
      }
    });

    test("throws NOT_INITIALIZED when no .trackgentic/ exists", () => {
      const uninitTracker = new Tracker(join(testDir, "nonexistent"));
      expect(uninitTracker.history("abc1234567")).rejects.toThrow(TrackgenticError);
    });
  });

  describe("full CRUD cycle", () => {
    test("create → list → view → update → view → history", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      // Create
      const created = await tracker.create({
        title: "CRUD Test",
        description: "Testing full cycle",
        status: "idea",
        priority: 2,
        assignee: "alice",
        tags: ["test"],
      });
      expect("id" in created).toBe(true);
      const id = "id" in created ? created.id : "";

      // List — should find the issue
      const listResult = await tracker.list();
      expect(listResult).toHaveLength(1);
      expect(listResult[0].id).toBe(id);
      expect(listResult[0].title).toBe("CRUD Test");

      // View — full computed state
      const view1 = await tracker.view(id);
      if ("title" in view1) {
        expect(view1.title).toBe("CRUD Test");
        expect(view1.description).toBe("Testing full cycle");
        expect(view1.status).toBe("idea");
        expect(view1.priority).toBe(2);
        expect(view1.assignee).toBe("alice");
        expect(view1.tags).toEqual(["test"]);
      }

      // Update
      await tracker.update(id, {
        title: "CRUD Updated",
        status: "done",
        priority: 1,
      });

      // View again — verify changes
      const view2 = await tracker.view(id);
      if ("title" in view2) {
        expect(view2.title).toBe("CRUD Updated");
        expect(view2.status).toBe("done");
        expect(view2.priority).toBe(1);
        // Unchanged fields persist
        expect(view2.assignee).toBe("alice");
        expect(view2.tags).toEqual(["test"]);
      }

      // History — should have creation + initial update + our update
      const history = await tracker.history(id);
      if (Array.isArray(history)) {
        expect(history).toHaveLength(3);
        expect(history[0].type).toBe("creation");
        expect(history[1].type).toBe("update");
        expect(history[2].type).toBe("update");
      }
    });
  });
});

import { afterEach, beforeEach, describe, expect, test } from "bun:test";
import { mkdirSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { spawn } from "bun";

const BIN_PATH = join(import.meta.dir, "..", "..", "src", "bin.ts");

describe("CLI commands", () => {
  let testDir: string;

  beforeEach(() => {
    testDir = join(
      tmpdir(),
      `trackgentic-cli-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    );
    mkdirSync(testDir, { recursive: true });
  });

  afterEach(() => {
    rmSync(testDir, { recursive: true, force: true });
  });

  async function runCLI(...args: string[]): Promise<{ stdout: string; stderr: string; exitCode: number }> {
    const proc = spawn({
      cmd: ["bun", "run", BIN_PATH, ...args],
      cwd: testDir,
      stdout: "pipe",
      stderr: "pipe",
    });

    const stdout = await new Response(proc.stdout).text();
    const stderr = await new Response(proc.stderr).text();
    const exitCode = await proc.exited;

    return { stdout, stderr, exitCode };
